// Code node: "Check duplicate"
// Run once per item

const staticData = $getWorkflowStaticData('global');

if (!staticData.processedKeys) {
  staticData.processedKeys = {};
}

// Use the already-normalized field from the previous "Normalize keys" Set node.
// Fallback to raw linkedin_url + lowercase/trim here too, in case this node
// ever runs standalone without the normalize step before it.
const rawKey = $input.item.json.linkedin_url_normalized || $input.item.json.linkedin_url || '';

const recordKey = String(rawKey)
  .trim()
  .toLowerCase()
  .replace(/\/$/, ''); // strip trailing slash

// Check if key exists — works for both boolean true (old) and object (new)
const isDuplicate = staticData.processedKeys[recordKey] !== undefined;

// Reserve the slot immediately so a second item with the same key
// in the same run is also caught as a duplicate
if (!isDuplicate && recordKey) {
  staticData.processedKeys[recordKey] = 'reserved';
}

return [{
  json: {
    ...$input.item.json,
    normalized_key: recordKey,
    duplicate: isDuplicate
  }
}];
